def gen(rng, size):
    n = rng.randint(1, max(1, min(size, 7)))
    s1 = ''.join(rng.choice('abc') for _ in range(n))
    def scramble(s):
        if len(s) <= 1:
            return s
        i = rng.randint(1, len(s) - 1)
        left = scramble(s[:i])
        right = scramble(s[i:])
        if rng.random() < 0.5:
            return left + right
        return right + left
    return [s1, scramble(s1)]

