class Solution:
    def isScramble(self, s1, s2):
        # naive: enumerate every scramble tree of s1 and test membership, no memo or pruning
        if len(s1) != len(s2):
            return False
        if sorted(s1) != sorted(s2):
            return False
        def all_scrambles(s):
            if len(s) == 1:
                return {s}
            out = set()
            for i in range(1, len(s)):
                for l in all_scrambles(s[:i]):
                    for r in all_scrambles(s[i:]):
                        out.add(l + r)
                        out.add(r + l)
            return out
        return s2 in all_scrambles(s1)

