var isScramble = function(s1, s2) {
    if (s1.length !== s2.length) return false;
    const memo = new Map();
    const sig = function(s) {
        const c = new Array(26).fill(0);
        for (const ch of s) c[ch.charCodeAt(0) - 97]++;
        return c.join(',');
    };
    const solve = function(a, b) {
        if (a === b) return true;
        const key = a + '#' + b;
        if (memo.has(key)) return memo.get(key);
        if (sig(a) !== sig(b)) { memo.set(key, false); return false; }
        const n = a.length;
        let ans = false;
        for (let i = 1; i < n && !ans; i++) {
            if (solve(a.slice(0, i), b.slice(0, i)) && solve(a.slice(i), b.slice(i))) ans = true;
            else if (solve(a.slice(0, i), b.slice(n - i)) && solve(a.slice(i), b.slice(0, n - i))) ans = true;
        }
        memo.set(key, ans);
        return ans;
    };
    return solve(s1, s2);
};
